def validate_quantum_numbers(n: int, l: int, m_l: int, m_s: float) -> dict:
    """
    Validate a set of quantum numbers.
    """
    errors = []
    orbital_letters = {0: 's', 1: 'p', 2: 'd', 3: 'f', 4: 'g', 5: 'h'}

    # Check principal quantum number
    if not isinstance(n, int) or n < 1:
        errors.append("n must be a positive integer (1, 2, 3, ...)")

    # Check angular momentum quantum number
    if not isinstance(l, int) or l < 0:
        errors.append("l must be a non-negative integer")
    elif n >= 1 and l >= n:
        errors.append(f"l must be less than n (l < {n})")

    # Check magnetic quantum number
    if not isinstance(m_l, int):
        errors.append("m_l must be an integer")
    elif l >= 0 and abs(m_l) > l:
        errors.append(f"m_l must be between -{l} and +{l}")

    # Check spin quantum number
    if m_s not in [0.5, -0.5]:
        errors.append("m_s must be +0.5 or -0.5")

    is_valid = len(errors) == 0

    result = {
        'valid': is_valid,
        'errors': errors
    }

    if is_valid:
        orbital_letter = orbital_letters.get(l, f'l={l}')
        result['orbital'] = f"{n}{orbital_letter}"

    return result

# Test cases
test_cases = [
    (2, 1, 0, 0.5),   # Should be valid: 2p
    (1, 1, 0, -0.5),  # Should be invalid: l >= n
    (3, 2, -2, 0.5),  # Should be valid: 3d
    (2, 0, 1, -0.5),  # Should be invalid: |m_l| > l
]

for n, l, m_l, m_s in test_cases:
    result = validate_quantum_numbers(n, l, m_l, m_s)
    print(f"n={n}, l={l}, m_l={m_l}, m_s={m_s}")
    print(f"  Valid: {result['valid']}")
    if result['valid']:
        print(f"  Orbital: {result['orbital']}")
    else:
        print(f"  Errors: {result['errors']}")
    print()
